function exportPokePaste(S){if(!S||!S.party)return;const lbl={hp:"HP",atk:"Atk",def:"Def",spa:"SpA",spd:"SpD",spe:"Spe"};const order=["hp","atk","def","spa","spd","spe"];const blocks=S.party.filter(m=>m).map(m=>{const L=[];let h=m.nick&&m.nick!==m.name?m.nick+" ("+m.name+")":m.name;if(m.gender==="♂")h+=" (M)";else if(m.gender==="♀")h+=" (F)";if(m.item)h+=" @ "+m.item;L.push(h);if(m.ability&&m.ability!=="—")L.push("Ability: "+m.ability);if(m.shiny)L.push("Shiny: Yes");if(m.level&&m.level!==100)L.push("Level: "+m.level);const ev=m.evs||{};const evp=order.filter(k=>ev[k]>0).map(k=>ev[k]+" "+lbl[k]).join(" / ");if(evp)L.push("EVs: "+evp);const iv=m.ivs||{};const ivp=order.filter(k=>iv[k]!==undefined&&iv[k]<31).map(k=>iv[k]+" "+lbl[k]).join(" / ");if(ivp)L.push("IVs: "+ivp);if(m.nature&&m.nature!=="—")L.push(m.nature+" Nature");(m.moves||[]).filter(mv=>mv).forEach(mv=>L.push("- "+mv));return L.join("\n")});const txt=blocks.join("\n\n");navigator.clipboard.writeText(txt).then(()=>alert("Team copied to clipboard!")).catch(()=>alert("Copy failed - check browser permissions"))}
